// componentKindHint returns a one-line description for each built-in
// component kind. Centralised here so renames/additions land in one
// place; the registry's Definition struct stays focused on runtime
// concerns. Unknown kinds get a generic fallback.
func componentKindHint(k components.Kind) string {
	switch k {
	case components.KindPosition:
		return "World coordinates."
	case components.KindVelocity:
		return "Per-tick movement vector."
	case components.KindSprite:
		return "Visible image — pulls from an asset."
	case components.KindCollider:
		return "Solid AABB for physics + interaction."
	case components.KindTile:
		return "Treats this entity as a paintable map tile."
	case components.KindStatic:
		return "Doesn't tick — locked to its starting cell."
	case "health":
		return "HP pool, damage handling, on-death triggers."
	case "inventory":
		return "Slots that hold items the player can swap."
	case "ai_behavior":
		return "FSM that decides movement + actions."
	case "spawner":
		return "Periodically creates other entities."
	case "resource":
		return "Counter (mana, ammo) automations can read or change."
	case "trigger":
		return "Fires automation when something enters its area."
	case "audio_emitter":
		return "Plays a sound from this entity's position."
	case "light_source":
		return "Casts a colored radius of light at runtime."
	default:
		return "Configurable behavior module."
	}
}

