// ---- helpers --------------------------------------------------------------

func automationsBlockID(entityTypeID int64) string {
	return fmt.Sprintf("automations-%d", entityTypeID)
}

func entityValues(et entities.EntityType) map[string]any {
	out := map[string]any{
		"name":                   et.Name,
		"collider_w":             et.ColliderW,
		"collider_h":             et.ColliderH,
		"collider_anchor_x":      et.ColliderAnchorX,
		"collider_anchor_y":      et.ColliderAnchorY,
		"default_collision_mask": et.DefaultCollisionMask,
		"tags":                   et.Tags,
	}
	if et.SpriteAssetID != nil {
		out["sprite_asset_id"] = *et.SpriteAssetID
	}
	if et.DefaultAnimationID != nil {
		out["default_animation_id"] = *et.DefaultAnimationID
	}
	return out
}

func decodeConfig(raw json.RawMessage) map[string]any {
	if len(raw) == 0 {
		return map[string]any{}
	}
	var m map[string]any
	if err := json.Unmarshal(raw, &m); err != nil {
		return map[string]any{}
	}
	return m
}

func alreadyAttached(k components.Kind, attached []entities.ComponentRow) bool {
	for _, c := range attached {
		if c.Kind == k {
			return true
		}
	}
	return false
}

// prefixField returns a copy of f with its Key prefixed (so multiple
// trigger/action sub-forms on the same page don't collide on field
// names). The renderer uses Key both for the input name and the label
// fallback, so prefixing is form-safe.
func prefixField(f configurable.FieldDescriptor, prefix string) configurable.FieldDescriptor {
	out := f
	out.Key = prefix + f.Key
	return out
}

// triggerHumanLabel turns a snake_case trigger kind into a user-readable
// label. Centralised so trigger renames only happen here; the registry
// stays the source of truth for kind strings.
func triggerHumanLabel(kind string) string {
	switch kind {
	case "entity_nearby":
		return "an entity is nearby"
	case "entity_absent":
		return "no entity nearby"
	case "resource_threshold":
		return "a resource crosses a threshold"
	case "timer":
		return "a timer ticks"
	case "on_spawn":
		return "this spawns"
	case "on_death":
		return "this dies"
	case "on_interact":
		return "a player interacts"
	case "on_enter_tile":
		return "this enters a tile"
	default:
		return kind
	}
}

// entityDeleteConfirm builds the delete confirm string with the real
// blast radius. UsedBy is a list of maps with this entity placed; each
// RailRef.Meta carries "× N" for the placement count on that map.
// Sum those Ns to tell the designer how many tiles will vanish.
func entityDeleteConfirm(usedBy []RailRef) string {
	tiles := 0
	for _, r := range usedBy {
		tiles += parsePlacementMeta(r.Meta)
	}
	if len(usedBy) == 0 {
		return "Delete this entity type? Components, automations, and tile-edge assignments go with it."
	}
	if len(usedBy) == 1 {
		return fmt.Sprintf("Delete this entity type? %d tile placement(s) on \"%s\" will be removed, plus components, automations, and tile-edge assignments.",
			tiles, usedBy[0].Label)
	}
	return fmt.Sprintf("Delete this entity type? %d tile placement(s) across %d maps will be removed, plus components, automations, and tile-edge assignments.",
		tiles, len(usedBy))
}

// parsePlacementMeta extracts the integer N from a RailRef.Meta value
// of the form "× N" (built by ConnectionsForEntity). Returns 0 for any
// other shape so the confirm degrades to "1 map" framing rather than
// claiming "0 placements".
func parsePlacementMeta(meta string) int {
	for i := 0; i < len(meta); i++ {
		c := meta[i]
		if c >= '0' && c <= '9' {
			n := 0
			for ; i < len(meta); i++ {
				d := meta[i]
				if d < '0' || d > '9' {
					break
				}
				n = n*10 + int(d-'0')
			}
			return n
		}
	}
	return 0
}

// removeActionConfirm returns the confirm string for the per-action ×
// button. With more than one action, removal is harmless; with one
// remaining, we tell the user the trigger config will stay (the server
// re-seeds a placeholder despawn, so trigger setup is preserved).
func removeActionConfirm(a automations.Automation, _ int) string {
	if len(a.Actions) <= 1 {
		return "Remove this action? The trigger config stays — we'll seed a placeholder so you can pick a new action."
	}
	return "Remove this action?"
}

// summarizeAction returns a one-line human description of an action
// node. Falls back to "<kind> (configured)" when the kind isn't known.
func summarizeAction(a automations.ActionNode) string {
	cfg := decodeConfig(a.Config)
	switch a.Kind {
	case "spawn":
		return fmt.Sprintf("spawn entity #%v", cfg["type_id"])
	case "despawn":
		if v, _ := cfg["target_self"].(bool); v {
			return "despawn self"
		}
		return "despawn target"
	case "move_toward":
		return fmt.Sprintf("move toward at %v sub-px/sec", cfg["speed_sub_per_sec"])
	case "move_away":
		return fmt.Sprintf("move away at %v sub-px/sec", cfg["speed_sub_per_sec"])
	case "set_speed":
		return fmt.Sprintf("set speed to %v sub-px/sec", cfg["speed_sub_per_sec"])
	case "set_sprite":
		return fmt.Sprintf("change sprite to asset #%v", cfg["asset_id"])
	case "set_animation":
		return fmt.Sprintf("play animation #%v", cfg["anim_id"])
	case "set_variant":
		return fmt.Sprintf("set palette variant #%v", cfg["variant_id"])
	case "set_tint":
		return fmt.Sprintf("tint %v for %v ms", cfg["color"], cfg["duration_ms"])
	case "play_sound":
		return fmt.Sprintf("play sound #%v at vol %v", cfg["sound_id"], cfg["volume"])
	case "emit_light":
		return fmt.Sprintf("emit light %v ms", cfg["duration_ms"])
	case "adjust_resource":
		return fmt.Sprintf("%+v %s", cfg["delta"], cfg["resource"])
	default:
		return a.Kind + " (configured)"
	}
}

